import React, { useState, useEffect, useRef } from 'react';
import { io } from 'socket.io-client';
import api from '../utils/api';

export default function BotPage() {
  const [running, setRunning] = useState(false);
  const [logs, setLogs] = useState([]);
  const [form, setForm] = useState({ keywords: '', location: '', limit: 20, autoSend: false });
  const [status, setStatus] = useState(null);
  const socketRef = useRef(null);
  const logsEndRef = useRef(null);

  useEffect(() => {
    const socket = io('http://localhost:3001');
    socketRef.current = socket;

    socket.on('bot:log', (data) => {
      setLogs((prev) => [...prev, { type: 'log', ...data, ts: new Date().toLocaleTimeString() }]);
    });
    socket.on('bot:lead', (lead) => {
      setLogs((prev) => [...prev, { type: 'lead', message: `Lead ajouté: ${lead.nom} (${lead.score}/10)`, ts: new Date().toLocaleTimeString() }]);
    });
    socket.on('bot:done', (data) => {
      setLogs((prev) => [...prev, { type: 'done', message: `Terminé — ${data.total} leads sauvegardés`, ts: new Date().toLocaleTimeString() }]);
      setRunning(false);
    });
    socket.on('bot:error', (data) => {
      setLogs((prev) => [...prev, { type: 'error', message: `Erreur: ${data.message}`, ts: new Date().toLocaleTimeString() }]);
      setRunning(false);
    });

    fetchStatus();
    return () => socket.disconnect();
  }, []);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs]);

  const fetchStatus = async () => {
    try {
      const { data } = await api.get('/bot/status');
      setStatus(data);
    } catch {}
  };

  const startBot = async () => {
    if (!form.keywords) return alert('Mots-clés requis');
    setLogs([]);
    setRunning(true);
    await api.post('/bot/start', form);
  };

  const stopBot = async () => {
    await api.post('/bot/stop');
    setRunning(false);
    setLogs((prev) => [...prev, { type: 'warn', message: 'Bot arrêté manuellement', ts: new Date().toLocaleTimeString() }]);
  };

  const LOG_COLORS = {
    log: 'text-gray-300',
    lead: 'text-green-400',
    done: 'text-indigo-400 font-bold',
    error: 'text-red-400',
    warn: 'text-yellow-400',
  };

  return (
    <div className="space-y-6 max-w-2xl">
      <h1 className="text-2xl font-bold">Bot Engine</h1>

      {/* Config */}
      <div className="bg-gray-900 rounded-lg border border-gray-800 p-5 space-y-4">
        <h2 className="text-sm font-semibold text-gray-400">Configuration</h2>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-xs text-gray-400 mb-1 block">Mots-clés *</label>
            <input
              className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
              placeholder="ex: CEO SaaS Paris"
              value={form.keywords}
              onChange={(e) => setForm({ ...form, keywords: e.target.value })}
            />
          </div>
          <div>
            <label className="text-xs text-gray-400 mb-1 block">Localisation</label>
            <input
              className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
              placeholder="ex: France"
              value={form.location}
              onChange={(e) => setForm({ ...form, location: e.target.value })}
            />
          </div>
          <div>
            <label className="text-xs text-gray-400 mb-1 block">Limite de leads</label>
            <input
              type="number"
              className="w-full bg-gray-800 border border-gray-700 rounded px-3 py-2 text-sm"
              value={form.limit}
              onChange={(e) => setForm({ ...form, limit: parseInt(e.target.value) })}
            />
          </div>
          <div className="flex items-center gap-2 mt-5">
            <input
              type="checkbox"
              id="autoSend"
              checked={form.autoSend}
              onChange={(e) => setForm({ ...form, autoSend: e.target.checked })}
              className="w-4 h-4"
            />
            <label htmlFor="autoSend" className="text-sm text-gray-300">Auto-envoyer emails</label>
          </div>
        </div>

        <div className="flex gap-3">
          <button
            onClick={startBot}
            disabled={running}
            className="px-5 py-2 bg-green-600 hover:bg-green-700 disabled:opacity-40 rounded font-medium text-sm"
          >
            {running ? '⏳ En cours...' : '▶ Démarrer'}
          </button>
          <button
            onClick={stopBot}
            disabled={!running}
            className="px-5 py-2 bg-red-600 hover:bg-red-700 disabled:opacity-40 rounded font-medium text-sm"
          >
            ⏹ Stopper
          </button>
        </div>
      </div>

      {/* Status */}
      {status && (
        <div className="flex gap-4 text-sm">
          {[['En attente', status.waiting], ['Actifs', status.active], ['Terminés', status.completed], ['Échoués', status.failed]].map(([label, val]) => (
            <div key={label} className="bg-gray-900 border border-gray-800 rounded px-3 py-2">
              <span className="text-gray-400">{label}: </span>
              <span className="font-bold">{val}</span>
            </div>
          ))}
        </div>
      )}

      {/* Logs */}
      <div className="bg-gray-950 rounded-lg border border-gray-800 p-4 h-72 overflow-y-auto font-mono text-xs">
        {logs.length === 0 ? (
          <p className="text-gray-600">En attente de démarrage...</p>
        ) : (
          logs.map((log, i) => (
            <div key={i} className={`${LOG_COLORS[log.type] || 'text-gray-300'} mb-1`}>
              <span className="text-gray-600">[{log.ts}]</span> {log.message}
            </div>
          ))
        )}
        <div ref={logsEndRef} />
      </div>
    </div>
  );
}
